Iteratively attempt to insert each ship into all existing assigns using a cost-aware greedy selection with fallback to a new empty assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for oidx := 0; oidx < orderCount; oidx++ {
		bestAssignIdx := -1
		bestDeltaCost := 1e18
		ori := oris[oidx]
		des := dess[oidx]
		shipID := total_ship + oidx

		candidates := make([]int, 0, dispatch.AssignsLen+1)
		for i := 0; i < dispatch.AssignsLen; i++ {
			candidates = append(candidates, i)
		}

		savedCosts := make(map[int]float64)
		savedStationLens := make(map[int]int)
		for _, idx := range candidates {
			assign := &dispatch.Assigns[idx]
			oldCost := assign.Cost
			oldSLen := assign.StationsLen
			savedCosts[idx] = oldCost
			savedStationLens[idx] = oldSLen

			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < bestDeltaCost {
						bestDeltaCost = delta
						bestAssignIdx = idx
					}
				}
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}

		fallbackNewEmpty := false
		targetIdx := bestAssignIdx
		if targetIdx == -1 {
			if dispatch.AssignsLen < MAXASSIGNS {
				targetIdx = dispatch.AssignsLen
				fallbackNewEmpty = true
			} else {
				targetIdx = dispatch.AssignsLen - 1
			}
		}

		success := false
		if fallbackNewEmpty {
			assign := &dispatch.Assigns[targetIdx]
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					success = true
					dispatch.AssignsLen++
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
		} else {
			assign := &dispatch.Assigns[targetIdx]
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					success = true
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
		}

		if !success && !fallbackNewEmpty {
			foundSafe := false
			for tryIdx := 0; tryIdx <= dispatch.AssignsLen; tryIdx++ {
				var assign *Assign
				isNew := false
				if tryIdx == dispatch.AssignsLen {
					if dispatch.AssignsLen < MAXASSIGNS {
						assign = &dispatch.Assigns[tryIdx]
						isNew = true
					} else {
						continue
					}
				} else {
					assign = &dispatch.Assigns[tryIdx]
				}

				ok := assign.AddShip(shipID, ori, des)
				if ok {
					assign.GenRoute()
					if assign.Cost >= 0 {
						foundSafe = true
						if isNew {
							dispatch.AssignsLen++
						}
						break
					} else {
						assign.RemoveShip(shipID)
						assign.GenRoute()
					}
				}
			}
			if !foundSafe && dispatch.AssignsLen < MAXASSIGNS {
				assign := &dispatch.Assigns[dispatch.AssignsLen]
				assign.AddShip(shipID, ori, des)
				assign.GenRoute()
				if assign.Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

